import{c as t,Q as i,j as s,m as a}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"How do I issue a credit?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/issue-credit.md","filePath":"guide/recipes/admin/issue-credit.md","lastUpdated":1779094756000}'),o={name:"guide/recipes/admin/issue-credit.md"};function r(n,e,l,c,d,u){return i(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="how-do-i-issue-a-credit" tabindex="-1">How do I issue a credit? <a class="header-anchor" href="#how-do-i-issue-a-credit" aria-label="Permalink to &quot;How do I issue a credit?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Finance Admin</strong></p></div><p>A credit reduces what a customer owes on their next invoice. Use it for goodwill adjustments, refunds, or pre-paid balances.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Finance → Finance Customers</strong> and click the customer.</li><li>Switch to the <strong>Credits</strong> tab.</li><li>Click <strong>Issue Credit</strong>.</li><li>Fill in: <ul><li><strong>Amount</strong> — in the customer&#39;s billing currency.</li><li><strong>Reason</strong> — visible on the customer&#39;s invoice and in audit.</li><li><strong>Effective from</strong> — usually today. Date-shift for retroactive adjustments.</li></ul></li><li>Click <strong>Issue</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The credit lands on the customer&#39;s credit balance. The next invoice automatically applies the credit before billing — if the credit exceeds the invoice amount, the surplus carries forward.</p><div class="tip custom-block"><p class="custom-block-title">Refunds vs. credits</p><p>A <strong>credit</strong> reduces a future invoice. A <strong>refund</strong> sends money back to the customer&#39;s bank/card and is handled outside the Console — record it as a payment with a negative amount once the funds clear.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./create-custom-plan">How do I create a custom plan?</a></li><li><a href="./configure-customer-billing">How do I configure billing for a customer?</a></li></ul>',10)])])}const p=t(o,[["render",r]]);export{m as __pageData,p as default};
